import{_ as t,o as e,c as r,a3 as o}from"./chunks/framework.BTFg6ESq.js";const b=JSON.parse('{"title":"📦 资产管理器 - 缩略图生成与展示","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/asset-manager/thumbnails-batch.md","filePath":"user-guide/tools/asset-manager/thumbnails-batch.md","lastUpdated":1778221347000}'),d={name:"user-guide/tools/asset-manager/thumbnails-batch.md"};function l(h,a,i,n,s,c){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="📦-资产管理器-缩略图生成与展示" tabindex="-1">📦 资产管理器 - 缩略图生成与展示 <a class="header-anchor" href="#📦-资产管理器-缩略图生成与展示" aria-label="Permalink to &quot;📦 资产管理器 - 缩略图生成与展示&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>资产管理器会自动为支持的资产生成视觉预览图（缩略图），让你在不打开文件的情况下快速识别内容。缩略图系统支持图片、视频和音频三种类型的资产，采用“前端生成+后端缓存”的混合模式。</p><blockquote><p><strong>核心价值：看一眼就知道是什么文件，无需逐个打开确认。</strong></p></blockquote><h2 id="缩略图支持的资产类型" tabindex="-1">缩略图支持的资产类型 <a class="header-anchor" href="#缩略图支持的资产类型" aria-label="Permalink to &quot;缩略图支持的资产类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资产类型</th><th>缩略图生成方式</th><th>效果</th></tr></thead><tbody><tr><td><strong>图片</strong></td><td>直接使用原图缩放</td><td>✅ 完整预览</td></tr><tr><td><strong>视频</strong></td><td>自动截取第一帧作为预览图</td><td>✅ 视频首帧快照</td></tr><tr><td><strong>音频</strong></td><td>提取内嵌专辑封面（如 MP3/FLAC）</td><td>✅ 专辑封面</td></tr><tr><td><strong>文档</strong></td><td>使用文件类型图标占位</td><td>❌ 无缩略图</td></tr></tbody></table><h3 id="图片缩略图" tabindex="-1">图片缩略图 <a class="header-anchor" href="#图片缩略图" aria-label="Permalink to &quot;图片缩略图&quot;">​</a></h3><p>图片类资产会直接使用原图并自动适应卡片尺寸展示。在网格视图中，你看到的预览区域就是图片的等比缩放缩略图。单击图片可打开内置图片查看器进行缩放、旋转等操作。</p><h3 id="视频缩略图" tabindex="-1">视频缩略图 <a class="header-anchor" href="#视频缩略图" aria-label="Permalink to &quot;视频缩略图&quot;">​</a></h3><p>视频类资产在首次加载时，前端会自动截取视频的第一帧作为缩略图。生成过程是<strong>异步的</strong>——在缩略图生成前会显示加载动画，生成后自动替换为视频首帧快照。</p><blockquote><p>TODO: 截图 - 视频资产在缩略图生成前/后的对比（加载动画 → 首帧预览）</p></blockquote><p>缩略图生成后会缓存到资产元数据中，下次打开时无需重新生成。</p><h3 id="音频缩略图" tabindex="-1">音频缩略图 <a class="header-anchor" href="#音频缩略图" aria-label="Permalink to &quot;音频缩略图&quot;">​</a></h3><p>如果音频文件（如 MP3、FLAC）内嵌了专辑封面图片，Rust 后端会自动提取并保存为缩略图。在资产卡片中会显示专辑封面，没有封面的音频文件会显示默认的音频文件图标。</p><blockquote><p>TODO: 截图 - 带专辑封面的音频资产卡片 vs 无封面的图标展示</p></blockquote><h2 id="缩略图显示优化" tabindex="-1">缩略图显示优化 <a class="header-anchor" href="#缩略图显示优化" aria-label="Permalink to &quot;缩略图显示优化&quot;">​</a></h2><h3 id="网格视图中的缩略图" tabindex="-1">网格视图中的缩略图 <a class="header-anchor" href="#网格视图中的缩略图" aria-label="Permalink to &quot;网格视图中的缩略图&quot;">​</a></h3><p>网格视图的卡片会以 <code>1:1</code> 的方形比例展示缩略图，图片会自动裁剪居中（<code>object-fit: cover</code>）。无论原图是什么尺寸，都会被流畅地展示在统一大小的预览框中。</p><p>网格视图支持三种卡片尺寸，适应不同场景：</p><table tabindex="0"><thead><tr><th>卡片尺寸</th><th>适用场景</th><th>缩略图大小</th></tr></thead><tbody><tr><td><strong>小卡片</strong></td><td>密集浏览大量资产</td><td>较小，一眼扫过</td></tr><tr><td><strong>中卡片</strong></td><td>默认模式，均衡</td><td>适中</td></tr><tr><td><strong>大卡片</strong></td><td>图片类资产预览为主</td><td>较大，看得清细节</td></tr></tbody></table><blockquote><p>TODO: 截图 - 三种卡片尺寸的对比展示</p></blockquote><h3 id="列表视图中的缩略图" tabindex="-1">列表视图中的缩略图 <a class="header-anchor" href="#列表视图中的缩略图" aria-label="Permalink to &quot;列表视图中的缩略图&quot;">​</a></h3><p>列表视图在文件名左侧会显示一个较小的缩略图（40px 方形），不占太多空间的同时提供视觉识别。</p><h3 id="加载占位" tabindex="-1">加载占位 <a class="header-anchor" href="#加载占位" aria-label="Permalink to &quot;加载占位&quot;">​</a></h3><p>视频等需要异步生成缩略图的资产，在加载过程中会显示一个旋转的加载动画（Spinner），避免空白区域的突兀感。</p><h2 id="缩略图处理机制" tabindex="-1">缩略图处理机制 <a class="header-anchor" href="#缩略图处理机制" aria-label="Permalink to &quot;缩略图处理机制&quot;">​</a></h2><h3 id="视频缩略图-前端截取" tabindex="-1">视频缩略图（前端截取） <a class="header-anchor" href="#视频缩略图-前端截取" aria-label="Permalink to &quot;视频缩略图（前端截取）&quot;">​</a></h3><p>视频缩略图的生成由前端驱动：</p><ol><li><strong>触发</strong>：当视频资产进入视口且尚未拥有缩略图时。</li><li><strong>生成</strong>：前端通过视频解码器截取第一帧并转换为 Base64 格式。</li><li><strong>持久化</strong>：生成的缩略图会自动发送给 Rust 后端并保存。下次加载时将直接从本地缓存读取，不再重复生成。</li></ol><h3 id="音频封面提取-后端解析" tabindex="-1">音频封面提取（后端解析） <a class="header-anchor" href="#音频封面提取-后端解析" aria-label="Permalink to &quot;音频封面提取（后端解析）&quot;">​</a></h3><p>音频文件的专辑封面提取由 Rust 后端利用 <code>lofty</code> 库实现：</p><ul><li>支持格式：MP3、FLAC 等带内嵌封面元数据的音频格式</li><li>提取时机：资产导入时自动进行</li><li>落盘位置：缩略图文件会保存在与资产对应的元数据目录中</li></ul><h2 id="异常情况处理" tabindex="-1">异常情况处理 <a class="header-anchor" href="#异常情况处理" aria-label="Permalink to &quot;异常情况处理&quot;">​</a></h2><h3 id="缩略图加载失败" tabindex="-1">缩略图加载失败 <a class="header-anchor" href="#缩略图加载失败" aria-label="Permalink to &quot;缩略图加载失败&quot;">​</a></h3><p>如果缩略图加载失败（例如图片损坏、视频无法解码、音频封面提取失败），系统会自动回退显示<strong>文件类型图标</strong>（通过 <code>FileIcon</code> 组件根据文件后缀匹配对应的图标），确保界面不会出现破碎的图片占位。</p><h3 id="视频缩略图生成失败" tabindex="-1">视频缩略图生成失败 <a class="header-anchor" href="#视频缩略图生成失败" aria-label="Permalink to &quot;视频缩略图生成失败&quot;">​</a></h3><p>视频缩略图生成依赖于前端的视频解码能力。如果遇到不支持的视频编码格式，缩略图可能无法生成，此时卡片会持续显示视频播放图标覆盖层的默认样式，不影响预览操作——单击仍可正常播放视频。</p><h2 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h2><h3 id="场景一-快速扫描图片库" tabindex="-1">场景一：快速扫描图片库 <a class="header-anchor" href="#场景一-快速扫描图片库" aria-label="Permalink to &quot;场景一：快速扫描图片库&quot;">​</a></h3><p>切换到网格视图并选择大卡片尺寸，可以直接浏览所有图片资产的缩略图，一眼找到需要的图片。</p><h3 id="场景二-区分多个视频文件" tabindex="-1">场景二：区分多个视频文件 <a class="header-anchor" href="#场景二-区分多个视频文件" aria-label="Permalink to &quot;场景二：区分多个视频文件&quot;">​</a></h3><p>视频缩略图展示了每个视频的第一帧画面，在网格视图中可以将不同内容的视频快速区分开，不需要逐个播放确认。</p><h3 id="场景三-识别音频专辑" tabindex="-1">场景三：识别音频专辑 <a class="header-anchor" href="#场景三-识别音频专辑" aria-label="Permalink to &quot;场景三：识别音频专辑&quot;">​</a></h3><p>导入多个音乐文件后，通过专辑封面缩略图快速识别不同的专辑和曲目，比纯文件名浏览直观得多。</p><blockquote><p>TODO: 截图 - 混合资产展示（图片缩略图、视频首帧、音频封面混合展示）</p></blockquote><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>回到<a href="./index">快速上手</a> — 掌握资产管理器的完整操作流程</li><li>学习<a href="./source-tracking">来源追踪</a> — 了解如何追溯资产的来源信息</li></ul>',47)])])}const p=t(d,[["render",l]]);export{b as __pageData,p as default};
